'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Search, Plus, Phone, Mail, Building2, User } from 'lucide-react';

interface Contacto {
  id: number;
  nombre: string;
  empresa: string;
  correo: string;
  telefono: string;
  estado: 'Activo' | 'Inactivo';
}

// Datos de ejemplo — reemplazar con llamada al servicio real cuando esté disponible
const contactosEjemplo: Contacto[] = [
  { id: 1, nombre: 'Ana García',      empresa: 'Resiflex S.A.',     correo: 'ana.garcia@resiflex.com',   telefono: '099-001-0001', estado: 'Activo' },
  { id: 2, nombre: 'Carlos Pérez',    empresa: 'Chaide & Chaide',   correo: 'carlos.perez@chaide.com',   telefono: '099-002-0002', estado: 'Activo' },
  { id: 3, nombre: 'María López',     empresa: 'Distribuidora XYZ', correo: 'maria.lopez@xyz.com',       telefono: '099-003-0003', estado: 'Inactivo' },
  { id: 4, nombre: 'Jorge Medina',    empresa: 'Resiflex S.A.',     correo: 'jorge.medina@resiflex.com', telefono: '099-004-0004', estado: 'Activo' },
  { id: 5, nombre: 'Lucía Torres',    empresa: 'ProventoGroup',     correo: 'lucia.torres@provento.com', telefono: '099-005-0005', estado: 'Activo' },
];

export default function ContactosPage() {
  const [contactos, setContactos] = useState<Contacto[]>(contactosEjemplo);
  const [busqueda, setBusqueda] = useState('');

  const contactosFiltrados = contactos.filter(c =>
    c.nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
    c.empresa.toLowerCase().includes(busqueda.toLowerCase()) ||
    c.correo.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="flex flex-col gap-6 p-6">
      {/* Encabezado */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Contactos</h1>
          <p className="text-muted-foreground text-sm">Gestión de contactos del CRM Resiflex</p>
        </div>
        <Button className="flex items-center gap-2 self-start sm:self-auto">
          <Plus className="h-4 w-4" />
          Nuevo Contacto
        </Button>
      </div>

      {/* Buscador */}
      <div className="relative max-w-sm">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
        <Input
          placeholder="Buscar por nombre, empresa o correo..."
          className="pl-9"
          value={busqueda}
          onChange={e => setBusqueda(e.target.value)}
        />
      </div>

      {/* Tarjetas de contactos */}
      {contactosFiltrados.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 text-muted-foreground gap-2">
          <User className="h-10 w-10 opacity-30" />
          <p>No se encontraron contactos</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {contactosFiltrados.map(contacto => (
            <Card key={contacto.id} className="hover:shadow-md transition-shadow cursor-pointer">
              <CardHeader className="pb-2">
                <div className="flex items-start justify-between gap-2">
                  <div className="flex items-center gap-2">
                    <div className="h-9 w-9 rounded-full bg-primary flex items-center justify-center text-primary-foreground font-semibold text-sm shrink-0">
                      {contacto.nombre.charAt(0).toUpperCase()}
                    </div>
                    <CardTitle className="text-base leading-tight">{contacto.nombre}</CardTitle>
                  </div>
                  <Badge variant={contacto.estado === 'Activo' ? 'default' : 'secondary'} className="shrink-0 text-xs">
                    {contacto.estado}
                  </Badge>
                </div>
              </CardHeader>
              <CardContent className="flex flex-col gap-1.5 text-sm text-muted-foreground">
                <div className="flex items-center gap-2">
                  <Building2 className="h-3.5 w-3.5 shrink-0" />
                  <span className="truncate">{contacto.empresa}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Mail className="h-3.5 w-3.5 shrink-0" />
                  <span className="truncate">{contacto.correo}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Phone className="h-3.5 w-3.5 shrink-0" />
                  <span>{contacto.telefono}</span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}
